{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate root — one of the most central entities in any logistics system. It affects data integrity for ~2M existing records, external partner API contracts, and downstream processes like routing, proof-of-delivery, billing, and notifications.",
    "bounded_context": "Shipment Management / Order Fulfillment — the core bounded context that governs how parcels move from sender to one or more recipients. This change radiates into adjacent contexts: Routing, Notifications, Billing, Partner Integration, and Proof of Delivery.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods moving through the logistics network from origin to one or more delivery destinations. The aggregate root." },
      { "term": "Recipient", "definition": "A party who receives all or part of a Shipment at a specific address. Has a name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preference", "definition": "A Recipient-level configuration governing how and when delivery should occur (e.g., leave at door, require signature, preferred time window, safe place instructions)." },
      { "term": "Primary Recipient", "definition": "The first or default Recipient on a multi-recipient Shipment. Critical for backward compatibility and as a fallback when a single contact is required." },
      { "term": "Delivery Stop", "definition": "A planned delivery point on a route, corresponding to one Recipient's address within a Shipment." },
      { "term": "Shipment Status", "definition": "The aggregate lifecycle state of a Shipment. In a multi-recipient model, must account for partial completion (some Recipients delivered, others pending)." },
      { "term": "Partner API Contract", "definition": "The external-facing data format and protocol used to exchange Shipment data with third-party systems. Currently assumes one Recipient per Shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A Shipment with zero Recipients has no delivery destination. It is physically meaningless — goods cannot be delivered to no one. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a Shipment with zero Recipients, or to remove the last Recipient from a Shipment, MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient MUST have a non-empty name, a valid address, and a valid phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically complete a delivery and contact the recipient. Without them, a courier cannot deliver or communicate.",
      "testable_assertion": "Persisting a Recipient with a null/empty name, null/invalid address, or null/invalid phone number MUST fail validation."
    },
    {
      "id": "BR-3",
      "rule": "All existing single-recipient Shipments MUST remain valid and queryable without data loss after migration.",
      "invariant": true,
      "invariant_justification": "Losing or corrupting ~2M production records would be a catastrophic data integrity failure with legal and financial consequences.",
      "testable_assertion": "After migration, querying any existing Shipment by ID returns the same Recipient data (name, address, phone) as before migration, now as a collection of one."
    },
    {
      "id": "BR-4",
      "rule": "Each Recipient within a Shipment MUST have independently trackable delivery status.",
      "invariant": true,
      "invariant_justification": "If Recipient A has been delivered but Recipient B has not, the system must reflect this. Collapsing status to a single value would make the system state corrupt — it would report either a false success or a false failure.",
      "testable_assertion": "A Shipment with Recipients [A, B] can be in a state where A=DELIVERED and B=IN_TRANSIT simultaneously, and querying the Shipment reflects both statuses."
    },
    {
      "id": "BR-5",
      "rule": "Delivery preferences are owned by each Recipient, not by the Shipment.",
      "invariant": false,
      "invariant_justification": "This is a design policy reflecting the product team's intent. A future VP could decide to add Shipment-level default preferences that Recipients inherit. The ownership model is a policy choice.",
      "testable_assertion": "Two Recipients on the same Shipment can have different delivery preferences (e.g., A requires signature, B allows safe-place), and each preference is respected independently."
    },
    {
      "id": "BR-6",
      "rule": "The Shipment aggregate's overall status MUST be derived deterministically from its Recipients' individual statuses.",
      "invariant": true,
      "invariant_justification": "If the aggregate status can diverge from the actual state of its parts, the system is in an inconsistent state. This is a data consistency invariant.",
      "testable_assertion": "A Shipment is COMPLETED only when ALL Recipients are DELIVERED. A Shipment is PARTIALLY_DELIVERED when at least one but not all Recipients are DELIVERED. A Shipment is FAILED only when ALL Recipients are FAILED or RETURNED."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs MUST continue to receive valid Shipment data in their expected format during and after transition.",
      "invariant": false,
      "invariant_justification": "This is a contractual and operational requirement, but the specific format and versioning strategy is a policy decision. Partners could be migrated to a new format over time.",
      "testable_assertion": "Partner API responses for single-recipient Shipments return data identical to the pre-migration format. Multi-recipient Shipments are either excluded from legacy endpoints or projected to a compatible format."
    },
    {
      "id": "BR-8",
      "rule": "A Shipment MUST designate exactly one Primary Recipient when multiple Recipients exist.",
      "invariant": false,
      "invariant_justification": "This is a policy to ensure backward compatibility and provide a default contact. It could be changed if external systems are all migrated. Not a physical or data-integrity constraint.",
      "testable_assertion": "A multi-recipient Shipment always has exactly one Recipient flagged as primary. Legacy API consumers receive the Primary Recipient when requesting the single-recipient view."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The caller provides two or more Recipients, each with valid name, address, phone, and distinct delivery preferences",
      "then": "The Shipment is persisted with all Recipients and their individual preferences; each Recipient has an independent delivery status initialized to PENDING"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before migration",
      "when": "The Shipment is queried via the API",
      "then": "The Recipient is returned as a collection of one, with all original data preserved and a Primary Recipient designation"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where Recipient A has been delivered",
      "when": "Recipient B's delivery fails",
      "then": "The Shipment status is PARTIALLY_DELIVERED (not FAILED), Recipient A remains DELIVERED, Recipient B is marked FAILED, and the Shipment is not considered complete"
    },
    {
      "id": "AC-4",
      "given": "An external partner API consumer using the legacy single-recipient format",
      "when": "They request data for any Shipment (old or new)",
      "then": "They receive the Primary Recipient in the existing flat format with no breaking changes; a versioned endpoint is available for multi-recipient data"
    },
    {
      "id": "AC-5",
      "given": "A Shipment with three Recipients",
      "when": "The caller attempts to remove all three Recipients",
      "then": "The operation is rejected and the Shipment retains at least one Recipient"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment with Recipients at different addresses",
      "when": "The routing engine plans delivery",
      "then": "Each Recipient generates an independent Delivery Stop, and the route accounts for multiple stops from a single Shipment"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient Shipment",
      "when": "All Recipients reach DELIVERED status",
      "then": "The Shipment aggregate status transitions to COMPLETED and billing is triggered once for the full Shipment"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Two Recipients on the same Shipment share the same address but have different delivery preferences (e.g., one requires signature, other allows safe place)",
      "expected_behavior": "Both Recipients are treated as distinct delivery obligations. The courier must satisfy each Recipient's preferences independently even at the same address. They may be consolidated into one physical stop but require separate proof-of-delivery."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already IN_TRANSIT",
      "expected_behavior": "Business must define whether mid-transit modification is allowed. If allowed, the routing engine must re-plan. If not, the addition is rejected. This is a critical policy decision that needs product clarification."
    },
    {
      "scenario": "Partner API receives a webhook for a multi-recipient Shipment but only understands single-recipient format",
      "expected_behavior": "The webhook payload projects the Primary Recipient for legacy consumers. New webhook versions include the full Recipient list. Partners are not silently dropped."
    },
    {
      "scenario": "A Shipment has 50 Recipients (stress/abuse case)",
      "expected_behavior": "A configurable upper bound on Recipients per Shipment must exist to prevent abuse and routing complexity explosion. Reject creation above the limit with a clear error."
    },
    {
      "scenario": "Partial delivery: 2 of 3 Recipients delivered, then the Shipment is cancelled",
      "expected_behavior": "Delivered Recipients cannot be un-delivered (physical constraint). Cancellation applies only to remaining PENDING/IN_TRANSIT Recipients. Billing reflects partial fulfillment. Shipment status becomes a terminal state like PARTIALLY_COMPLETED_CANCELLED."
    },
    {
      "scenario": "Data migration of 2M records: mid-migration failure",
      "expected_behavior": "Migration must be idempotent and resumable. Partially migrated state must not corrupt reads. Dual-read capability (old format and new format) should be active during migration window."
    },
    {
      "scenario": "Recipient-level notifications: one Recipient opts out of SMS, another wants real-time updates",
      "expected_behavior": "Notification preferences are per-Recipient. The notification system must fan out per Recipient, not per Shipment. Existing single-recipient notification logic must still work for legacy Shipments."
    }
  ],

  "business_impact": {
    "financial": "Medium-to-high impact. Multi-recipient Shipments likely enable new revenue (e.g., multi-drop services, group orders). However, the billing model must be redefined — is it per-Shipment or per-Recipient? Incorrect billing logic during transition could cause revenue leakage. Migration costs include engineering effort, partner coordination, and potential downtime.",
    "operational": "High impact. Routing engines must support multiple stops per Shipment. Courier workflows change — a single scan-and-deliver becomes a multi-stop obligation. Proof-of-delivery must be collected per Recipient. Operational dashboards and SLA tracking must account for partial delivery states. Support teams need training on new Shipment statuses.",
    "user": "Positive for senders who need multi-drop delivery. Potentially confusing for Recipients if notifications reference a shared Shipment they don't understand. Courier experience becomes more complex — they now carry partial-completion responsibility per Shipment.",
    "risk": "HIGH. This touches the core aggregate root. Risks include: (1) data migration failure or corruption of 2M records, (2) breaking external partner integrations silently, (3) inconsistent Shipment status logic causing operational blind spots, (4) billing errors during transition, (5) routing engine unable to handle multi-stop efficiently leading to SLA breaches.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain new multi-recipient capability. Must learn new UI/API for managing multiple Recipients. Existing workflows unchanged for single-recipient shipments." },
      { "group": "Recipients", "impact": "May receive notifications referencing a shared Shipment. Delivery preferences now independently respected. No action required from existing Recipients." },
      { "group": "Couriers/Drivers", "impact": "Significant workflow change. Must handle multiple delivery stops per Shipment, collect per-Recipient proof-of-delivery, and manage partial completion states on their device." },
      { "group": "External API Partners", "impact": "Highest disruption risk. Must be notified, given migration timeline, and provided backward-compatible endpoints. Silent breakage would damage trust and contractual obligations." },
      { "group": "Customer Support", "impact": "Must handle new status types (PARTIALLY_DELIVERED). Needs updated tooling and training to investigate multi-recipient Shipments." },
      { "group": "Finance/Billing Team", "impact": "Billing model must be clarified before launch. Per-Shipment vs per-Recipient pricing has direct revenue implications." },
      { "group": "Operations/Dispatch", "impact": "Route optimization becomes more complex. SLA definitions may need revision for multi-recipient Shipments." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec clearly defines the direction (1-to-many Recipient relationship with per-Recipient preferences) but leaves several critical business decisions unspecified: billing model, mid-transit modification policy, maximum Recipient count, Shipment-level status derivation rules, and partner migration strategy. These gaps prevent high confidence in complete acceptance criteria.",
    "high_confidence_areas": [
      "Core cardinality change from 1:1 to 1:N is well-defined",
      "Backward compatibility for 2M existing records is a hard requirement",
      "Per-Recipient delivery preferences are explicitly requested",
      "External partner API impact is a known risk"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient Shipments (per-Shipment vs per-Recipient vs per-stop)",
      "Whether Recipients can be added/removed from in-transit Shipments",
      "Maximum number of Recipients allowed per Shipment",
      "How Shipment-level status is derived from Recipient statuses (specific state machine)",
      "Partner API versioning and migration strategy details",
      "Whether proof-of-delivery is per-Recipient or per-Shipment"
    ],
    "assumptions": [
      "Existing single-recipient Shipments must remain fully functional without requiring sender action",
      "A Primary Recipient concept is needed for backward compatibility with legacy consumers",
      "Delivery preferences include but are not limited to: time windows, signature requirements, safe-place instructions",
      "The Shipment remains a single aggregate root rather than being split into separate entities per Recipient"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The billing model for multi-recipient Shipments is undefined. Is a 3-recipient Shipment billed as one shipment, three shipments, or a base fee plus per-recipient surcharge? This fundamentally affects pricing, invoicing, and revenue recognition.",
      "affected_stakeholders": ["Finance/Billing Team", "Senders/Shippers", "External API Partners"],
      "options": [
        "Per-Shipment flat rate regardless of Recipient count",
        "Per-Recipient billing (each Recipient is a line item)",
        "Base Shipment fee plus incremental per-Recipient surcharge"
      ],
      "recommendation": "Per-Recipient surcharge model — aligns cost with operational complexity (more stops = more cost) while keeping a single Shipment as the billing anchor."
    },
    {
      "type": "ambiguity",
      "description": "Can Recipients be added or removed from a Shipment after it enters IN_TRANSIT status? This affects routing, courier workflows, and system complexity significantly.",
      "affected_stakeholders": ["Couriers/Drivers", "Operations/Dispatch", "Senders/Shippers"],
      "options": [
        "Immutable after dispatch — Recipients locked once Shipment is IN_TRANSIT",
        "Mutable with re-routing — Recipients can be added/removed, triggering route recalculation",
        "Additive only — new Recipients can be added but existing ones cannot be removed once dispatched"
      ],
      "recommendation": "Immutable after dispatch for v1. Mid-transit modification is operationally complex and can be added as a future enhancement once the base model is stable."
    },
    {
      "type": "ambiguity",
      "description": "The Shipment-level status state machine for multi-recipient scenarios is not defined. What does it mean for a Shipment to be 'DELIVERED' when it has 3 Recipients and only 2 are delivered?",
      "affected_stakeholders": ["Customer Support", "Operations/Dispatch", "Senders/Shippers"],
      "options": [
        "Introduce PARTIALLY_DELIVERED as a new Shipment status",
        "Shipment status is always the 'worst' Recipient status",
        "Shipment status is derived: COMPLETED only when all Recipients are in a terminal state"
      ],
      "recommendation": "Introduce PARTIALLY_DELIVERED and derive Shipment status deterministically: COMPLETED when all delivered, PARTIALLY_DELIVERED when mixed, FAILED when all failed."
    },
    {
      "type": "missing_context",
      "description": "No maximum Recipient count per Shipment is specified. Without an upper bound, the routing engine, UI, and notification systems could face unbounded complexity.",
      "affected_stakeholders": ["Operations/Dispatch", "Couriers/Drivers", "Engineering"],
      "options": [
        "Hard limit of 5 Recipients per Shipment",
        "Hard limit of 10 Recipients per Shipment",
        "Configurable per account/tier with a system-wide ceiling"
      ],
      "recommendation": "Configurable per account with a system-wide ceiling of 10 for v1. This prevents abuse while allowing flexibility for enterprise customers."
    }
  ],

  "rejection_reasons": []
}

